codingChallenges.solution:
age = int(input("Enter your age: "))
if age >= 18:
    print("You can vote!")
else:
    years_left = 18 - age
    print("You cannot vote yet. Wait", years_left, "more years.")

age = int(input("Enter age: "))
if age < 12:
    price = 100
elif age <= 17:
    price = 200
elif age <= 59:
    price = 300
else:
    price = 150
print("Ticket price: Rs", price)

a = int(input("Side 1: "))
b = int(input("Side 2: "))
c = int(input("Side 3: "))

if a + b > c and b + c > a and a + c > b:
    print("Valid triangle")
    if a == b == c:
        print("Type: Equilateral")
    elif a == b or b == c or a == c:
        print("Type: Isosceles")
    else:
        print("Type: Scalene")
else:
    print("Not a valid triangle")

marks = int(input("Enter marks: "))
if marks < 0 or marks > 100:
    print("Invalid marks! Must be 0-100.")
elif marks >= 90:
    print("Grade: A")
    print("Remark: Excellent")
elif marks >= 80:
    print("Grade: B")
    print("Remark: Excellent")
elif marks >= 70:
    print("Grade: C")
    print("Remark: Good")
elif marks >= 60:
    print("Grade: D")
    print("Remark: Good")
elif marks >= 40:
    print("Grade: E")
    print("Remark: Pass")
else:
    print("Grade: F")
    print("Remark: Fail")

year = int(input("Enter year: "))
if (year % 4 == 0 and year % 100 != 0) or (year % 400 == 0):
    print(year, "is a leap year")
else:
    print(year, "is NOT a leap year")

num1 = float(input("Enter first number: "))
num2 = float(input("Enter second number: "))
op = input("Enter operation (+, -, *, /): ")

if op == "+":
    print("Result:", num1 + num2)
elif op == "-":
    print("Result:", num1 - num2)
elif op == "*":
    print("Result:", num1 * num2)
elif op == "/":
    if num2 == 0:
        print("Error: Cannot divide by zero!")
    else:
        print("Result:", num1 / num2)
else:
    print("Invalid operation!")

weight = float(input("Enter weight (kg): "))
height = float(input("Enter height (m): "))

if weight <= 0 or height <= 0:
    print("Error: Weight and height must be positive.")
else:
    bmi = weight / (height ** 2)
    bmi_rounded = round(bmi, 1)
    print("BMI:", bmi_rounded)

    if bmi < 18.5:
        print("Category: Underweight")
    elif bmi < 25:
        print("Category: Normal weight")
    elif bmi < 30:
        print("Category: Overweight")
    else:
        print("Category: Obese")

units = int(input("Enter units consumed: "))
fixed_charge = 100

if units <= 100:
    bill = units * 5
elif units <= 200:
    bill = 100 * 5 + (units - 100) * 7
elif units <= 300:
    bill = 100 * 5 + 100 * 7 + (units - 200) * 10
else:
    bill = 100 * 5 + 100 * 7 + 100 * 10 + (units - 300) * 15

total = bill + fixed_charge
print("Units:", units)
print("Total bill: Rs", total)

num = int(input("Enter a number: "))

if num > 0:
    print(num, "is positive")
elif num < 0:
    print(num, "is negative")
else:
    print(num, "is zero")

if num != 0:
    if num % 2 == 0:
        print(num, "is even")
    else:
        print(num, "is odd")

if num % 5 == 0 and num != 0:
    print(num, "is divisible by 5")

if num % 3 == 0 and num != 0:
    print(num, "is divisible by 3")

abs_num = abs(num)
if 0 <= abs_num <= 9:
    print(num, "is a single digit number")
elif 10 <= abs_num <= 99:
    print(num, "is a two-digit number")
elif 100 <= abs_num <= 999:
    print(num, "is a three-digit number")

password = input("Enter password: ")
length = len(password)

has_digit = False
has_upper = False
for char in password:
    if char.isdigit():
        has_digit = True
    if char.isupper():
        has_upper = True

if length >= 10 and has_digit and has_upper:
    print("Password strength: Strong")
elif length >= 6 and has_digit:
    print("Password strength: Medium")
else:
    print("Password strength: Weak")
